const body = $input.first().json.body || $input.first().json;

const produit = body.produit || 'Produit inconnu';
const ferme = body.ferme || 'Ferme inconnue';
const quantite = body.quantite_actuelle ?? 0;
const seuil = body.seuil_alerte ?? 0;
const unite = body.unite || 'unités';

const sujet = `⚠️ ALERTE STOCK — ${produit} (${ferme})`;

const messageEmail = `Bonjour,

Une alerte de stock a été déclenchée automatiquement par Farm Manager.

📦 Produit     : ${produit}
🏡 Ferme       : ${ferme}
📉 Stock actuel : ${quantite} ${unite}
🚨 Seuil alerte : ${seuil} ${unite}

Merci de procéder au réapprovisionnement dans les plus brefs délais.

---
Farm Manager — Système automatisé`;

const messageWhatsApp = `⚠️ *ALERTE STOCK*

📦 *${produit}*
🏡 ${ferme}

📉 Stock : *${quantite} ${unite}*
🚨 Seuil : ${seuil} ${unite}

Réapprovisionnement nécessaire.`;

return [{
  json: {
    produit,
    ferme,
    quantite,
    seuil,
    unite,
    sujet,
    messageEmail,
    messageWhatsApp,
    timestamp: new Date().toLocaleString('fr-TN', { timeZone: 'Africa/Tunis' })
  }
}];
